command:
mkdir -p .claude-tdd-pro && printf 'sources:
  - {id: a, source_class: financial-industry, tier: 1, applies_to: [node]}
  - {id: b, source_class: financial-industry, tier: 1, applies_to: [node]}
operator_namespace: []
' > .claude-tdd-pro/PR-SOURCES.yaml && bash "$CLAUDE_PLUGIN_ROOT/pr-corpus/sync-from-sources.sh" --registry .claude-tdd-pro/PR-SOURCES.yaml --dry-run 2>out.txt && grep -q 'sources_to_sync=2' out.txt && grep -q 'a' out.txt && grep -q 'b' out.txt && echo ok 1>&2
